// Recebe o HTML bruto do nó anterior
const html = $json["data"]; // ajuste conforme o campo que contém o HTML

// Função auxiliar para extrair dados com regex
function extractAll(regex, text) {
  const results = [];
  let match;
  while ((match = regex.exec(text)) !== null) {
    results.push(match[1].trim());
  }
  return results;
}

// Extrair títulos dos produtos
const titulos = extractAll(/<span class="a-size-medium.*?">(.*?)<\/span>/g, html);

// Extrair preços
const precos = extractAll(/<span class="p13n-sc-price">(.*?)<\/span>/g, html);

// Extrair links
const links = extractAll(/<a class="a-link-normal" href="(.*?)"/g, html)
  .map(l => "https://www.amazon.com.br" + l);

// Montar lista de produtos
const produtos = titulos.map((t, i) => ({
  titulo: t,
  preco: precos[i] || null,
  link: links[i] || null
}));

return [{ produtos }];
